18	function makeEntry(overrides: Partial<IndexEntry> = {}): IndexEntry {
19	  return {
20	    id: "abc123test",
21	    title: "Test Issue",
22	    path: "issues/abc123test.json",
23	    status: "idea",
24	    assignee: null,
25	    parentId: null,
26	    tags: [],
27	    priority: 3,
28	    ...overrides,
29	  };
30	}
31	
32	function makeIndex(entries: IndexEntry[]): IndexFile {
33	  const index: IndexFile = { open: [], closed: [], childrenOf: {} };
34	  for (const entry of entries) {
35	    if (entry.status === "closed") {
36	      index.closed.push(entry);
37	    } else {
38	      index.open.push(entry);
39	    }
40	    if (entry.parentId) {
41	      if (!index.childrenOf[entry.parentId]) {
42	        index.childrenOf[entry.parentId] = [];
43	      }
44	      index.childrenOf[entry.parentId].push(entry.id);
45	    }
46	  }
47	  return index;
48	}
