154	  /**
155	   * Initialize a new `.trackgentic/` directory in `cwd`.
156	   */
157	  async init(): Promise<InitResult> {
158	    const trackerDir = join(this.cwd, TRACKGENTIC_DIR);
159	
160	    if (existsSync(trackerDir)) {
161	      return { result: "ALREADY_INITIALIZED", path: resolve(trackerDir) };
162	    }
163	
164	    mkdirSync(trackerDir, { recursive: true });
165	    mkdirSync(join(trackerDir, "issues"), { recursive: true });
