167	    await atomicWriteJSON(join(trackerDir, "config.json"), DEFAULT_CONFIG);
168	    await atomicWriteJSON(join(trackerDir, "index.json"), DEFAULT_INDEX);
169	    await atomicWriteJSON(join(trackerDir, "dependencies.json"), DEFAULT_DEPENDENCIES);
170	    await atomicWriteJSON(join(trackerDir, "users.json"), DEFAULT_USERS);
171	
172	    return { result: "OK", path: resolve(trackerDir) };
