175	  /**
176	   * Create a new issue.
177	   */
178	  async create(params: CreateParams): Promise<CreateResult> {
179	    const trackerDir = resolveTrackerDir(this.cwd);
180	    if (!trackerDir) {
181	      throw new TrackgenticError(
182	        ErrorCodes.NOT_INITIALIZED.result,
183	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
184	        ErrorCodes.NOT_INITIALIZED.exitCode,
185	      );
186	    }
187	
188	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
189	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
190	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
191	    if (authResult instanceof TrackgenticError) return authResult;
192	    const author = params.author ?? authResult.author;
193	
194	    const id = generateId();
195	    const issuePath = params.path ?? `issues/${id}.json`;
196	    const now = new Date().toISOString();
197	
198	    const title = params.title;
199	    const description = params.description ?? "";
200	    const status: IssueStatus = params.status ?? "idea";
201	    const priority = params.priority ?? 3;
202	    const assignee = params.assignee ?? null;
203	    const parentId = params.parentId ?? null;
204	    const tags = params.tags ?? [];
205	
206	    // Read index early for parent validation
207	    const index = await readIndex(trackerDir);
208	
209	    // Validate parent exists and is not closed
210	    if (parentId) {
211	      const parentEntry = findEntry(index, parentId);
212	      if (!parentEntry) {
213	        throw new TrackgenticError(
214	          ErrorCodes.NOT_FOUND.result,
215	          "Parent issue not found",
216	          ErrorCodes.NOT_FOUND.exitCode,
217	        );
218	      }
219	      const validationError = validateNewChild(parentEntry);
220	      if (validationError) {
221	        throw new TrackgenticError(
222	          ErrorCodes.HIERARCHY_CONSTRAINT.result,
223	          validationError,
224	          ErrorCodes.HIERARCHY_CONSTRAINT.exitCode,
225	        );
226	      }
227	    }
228	
229	    // Build update content with only non-default values
230	    const updateContent: Partial<
231	      Pick<
232	        IssueProperties,
233	        "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId"
234	      >
235	    > & { title: string } = { title };
236	    if (description) updateContent.description = description;
237	    if (status !== "idea") updateContent.status = status;
238	    if (priority !== 3) updateContent.priority = priority;
239	    if (assignee !== null) updateContent.assignee = assignee;
240	    if (parentId !== null) updateContent.parentId = parentId;
241	    if (tags.length > 0) updateContent.tags = tags;
242	
243	    // Create issue file with two events: creation + update
244	    const creationEvent = { type: "creation" as const, timestamp: now, author };
245	    const updateEvent = {
246	      type: "update" as const,
247	      timestamp: now,
248	      author,
249	      content: updateContent,
250	    };
251	
252	    const issueFilePath = join(trackerDir, issuePath);
253	    await atomicWriteJSON(issueFilePath, [creationEvent, updateEvent]);
254	
255	    // Build index entry and insert into index
256	    const entry: IndexEntry = {
257	      id,
258	      title,
259	      path: issuePath,
260	      status,
261	      assignee,
262	      parentId,
263	      tags,
264	      priority,
265	    };
266	
267	    const updatedIndex = insertEntry(index, entry);
268	    await writeIndex(trackerDir, updatedIndex);
269	
270	    return { id };
271	  }
