273	  /**
274	   * List issues from the index, with optional filters.
275	   */
276	  async list(params?: ListParams): Promise<ListResult> {
277	    const trackerDir = resolveTrackerDir(this.cwd);
278	    if (!trackerDir) {
279	      throw new TrackgenticError(
280	        ErrorCodes.NOT_INITIALIZED.result,
281	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
282	        ErrorCodes.NOT_INITIALIZED.exitCode,
283	      );
284	    }
285	
286	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
287	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
288	    const authResult = resolveAuthor({ config, users, requiresWrite: false });
289	    if (authResult instanceof TrackgenticError) {
290	      throw authResult;
291	    }
292	
293	    const index = await readIndex(trackerDir);
294	
295	    // Determine source arrays based on params.status
296	    let entries: IndexEntry[];
297	    if (params?.status === "closed") {
298	      entries = index.closed;
299	    } else if (params?.status === "open") {
300	      entries = index.open;
301	    } else if (params?.status) {
302	      entries = index.open;
303	    } else {
304	      entries = [...index.open, ...index.closed];
305	    }
306	
307	    // Filter in memory
308	    let filtered = entries;
309	
310	    if (params?.status && params.status !== "open" && params.status !== "closed") {
311	      filtered = filtered.filter((e) => e.status === params.status);
312	    }
313	
314	    if (params?.assignee) {
315	      filtered = filtered.filter((e) => e.assignee === params.assignee);
316	    }
317	
318	    if (params?.tags && params.tags.length > 0) {
319	      filtered = filtered.filter((e) => params.tags?.every((tag) => e.tags.includes(tag)));
320	    }
321	
322	    if (params?.parentId !== undefined) {
323	      if (params.parentId === null) {
324	        filtered = filtered.filter((e) => e.parentId === null);
325	      } else {
326	        filtered = filtered.filter((e) => e.parentId === params.parentId);
327	      }
328	    }
329	
330	    // Sort: priority ASC → id ASC
331	    filtered.sort((a, b) => {
332	      if (a.priority !== b.priority) return a.priority - b.priority;
333	      return a.id.localeCompare(b.id);
334	    });
335	
336	    return filtered;
337	  }
