410	      );
411	    }
412	
413	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
414	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
415	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
416	    if (authResult instanceof TrackgenticError) return authResult;
417	    const author = params.author ?? authResult.author;
418	
419	    const index = await readIndex(trackerDir);
420	    const entry = findEntry(index, id);
421	    if (!entry) {
422	      throw new TrackgenticError(
423	        ErrorCodes.NOT_FOUND.result,
424	        `Issue ${id} not found in index.`,
425	        ErrorCodes.NOT_FOUND.exitCode,
426	      );
427	    }
428	
429	    const issueFilePath = join(trackerDir, entry.path);
430	    if (!existsSync(issueFilePath)) {
431	      throw new TrackgenticError(
432	        ErrorCodes.ISSUE_MISSING.result,
433	        `Issue file for ${id} is missing.`,
434	        ErrorCodes.ISSUE_MISSING.exitCode,
435	      );
436	    }
437	
438	    // Save old values for hierarchy handling
439	    const oldStatus = entry.status;
440	    const oldParentId = entry.parentId;
441	
442	    // ── Hierarchy validation (before any state changes) ────────────
443	
444	    // Validate downward constraints for status change
445	    if (params.status !== undefined && params.status !== oldStatus) {
446	      if (params.status === "done" || params.status === "closed") {
447	        const childIds = getChildren(index, id);
448	        const childEntries = childIds
449	          .map((cid) => findEntry(index, cid))
