874	  async usersRegister(name: string): Promise<UsersRegisterResult> {
875	    const trackerDir = resolveTrackerDir(this.cwd);
876	    if (!trackerDir) {
877	      throw new TrackgenticError(
878	        ErrorCodes.NOT_INITIALIZED.result,
879	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
880	        ErrorCodes.NOT_INITIALIZED.exitCode,
881	      );
882	    }
883	
884	    const lowerName = name.toLowerCase();
885	
886	    // Reject reserved name
887	    if (lowerName === "anonymous") {
888	      return {
889	        result: "USER_ALREADY_EXISTS",
890	        message: `"anonymous" is a reserved name and cannot be registered.`,
891	      };
892	    }
893	
894	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
895	
896	    // Check uniqueness
897	    if (users.users.find((u) => u.name === lowerName)) {
898	      return {
899	        result: "USER_ALREADY_EXISTS",
900	        message: `User "${lowerName}" already exists.`,
901	      };
902	    }
903	
904	    const token = generateToken();
905	    const newUser: UserEntry = {
906	      name: lowerName,
907	      token,
908	      registeredAt: new Date().toISOString(),
909	    };
910	
911	    users.users.push(newUser);
912	    await atomicWriteJSON(join(trackerDir, "users.json"), users);
913	
914	    return { result: "OK", name: lowerName, token };
915	  }
