1	import type { CommentId, IssueId, IssueProperties } from "./issue";
2	
3	/**
4	 * Base shape for all events.
5	 */
6	export interface BaseEvent {
7	  timestamp: string; // ISO 8601
8	  author: string; // resolved user name or "system"
9	}
10	
11	/**
12	 * Creation event — marks the birth of an issue. No content.
13	 */
14	export interface CreationEvent extends BaseEvent {
15	  type: "creation";
16	}
17	
18	/**
19	 * Update event — records changes to issue properties.
20	 */
21	export interface UpdateEvent extends BaseEvent {
22	  type: "update";
23	  content: Partial<
24	    Pick<
25	      IssueProperties,
26	      "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId"
27	    >
28	  > & {
29	    reason?: string; // for system auto-promotion events
30	  };
31	}
32	
33	/**
34	 * Comment event — adds a new comment.
35	 */
36	export interface CommentEvent extends BaseEvent {
37	  type: "comment";
38	  content: {
39	    id: CommentId;
40	    content: string;
41	  };
42	}
43	
44	/**
45	 * Comment update event — edits an existing comment.
46	 */
47	export interface CommentUpdateEvent extends BaseEvent {
48	  type: "comment-update";
49	  content: {
50	    id: CommentId;
51	    content: string;
52	  };
53	}
54	
55	/**
56	 * Comment delete event — soft-deletes a comment.
57	 */
58	export interface CommentDeleteEvent extends BaseEvent {
59	  type: "comment-delete";
60	  content: {
61	    id: CommentId;
62	  };
63	}
64	
65	/**
66	 * Blockage added event — records a new dependency.
67	 */
68	export interface BlockageAddedEvent extends BaseEvent {
69	  type: "blockage-added";
70	  content: {
71	    blockerId: IssueId;
72	  };
73	}
74	
75	/**
76	 * Blockage resolved event — records dependency resolution.
77	 */
78	export interface BlockageResolvedEvent extends BaseEvent {
79	  type: "blockage-resolved";
80	  content: {
81	    blockerId: IssueId;
82	  };
83	}
84	
85	/**
86	 * Blockage deleted event — records dependency removal.
87	 */
88	export interface BlockageDeletedEvent extends BaseEvent {
89	  type: "blockage-deleted";
90	  content: {
91	    blockerId: IssueId;
92	  };
93	}
94	
95	/**
96	 * Union of all event types.
97	 */
98	export type Event =
99	  | CreationEvent
100	  | UpdateEvent
101	  | CommentEvent
102	  | CommentUpdateEvent
103	  | CommentDeleteEvent
104	  | BlockageAddedEvent
105	  | BlockageResolvedEvent
106	  | BlockageDeletedEvent;
